const raw = $input.first().json || {};

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value);
}

function isNonEmptyObject(value) {
  return isObject(value) && Object.keys(value).length > 0;
}

function firstNonEmptyObject(...values) {
  for (const value of values) {
    if (isNonEmptyObject(value)) return value;
  }
  return {};
}

function cleanString(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseJsonFlexible(value) {
  if (value === undefined || value === null) return {};

  if (typeof value === 'object') return value;

  let text = String(value).trim();

  text = text
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return {
      __parse_error: true,
      __parse_error_message: error.message,
      __raw_text: value
    };
  }
}

function unwrapBrunaOutput(rawValue) {
  const parsedLevel1 = parseJsonFlexible(rawValue);

  if (parsedLevel1?.output !== undefined) {
    const parsedLevel2 = parseJsonFlexible(parsedLevel1.output);

    if (parsedLevel2?.output && typeof parsedLevel2.output === 'object') {
      return {
        bruna: parsedLevel2.output,
        parse_error: false,
        raw_parsed: parsedLevel2
      };
    }

    if (parsedLevel1.output && typeof parsedLevel1.output === 'object') {
      return {
        bruna: parsedLevel1.output,
        parse_error: false,
        raw_parsed: parsedLevel1
      };
    }

    return {
      bruna: parsedLevel2,
      parse_error: parsedLevel2.__parse_error === true,
      raw_parsed: parsedLevel2
    };
  }

  return {
    bruna: parsedLevel1,
    parse_error: parsedLevel1.__parse_error === true,
    raw_parsed: parsedLevel1
  };
}

function toBool(value) {
  return value === true || value === 1 || value === '1' || String(value).toLowerCase() === 'true';
}

function enumValue(value, allowed, fallback) {
  const v = cleanString(value);
  return allowed.includes(v) ? v : fallback;
}

function chooseString(next, previous = '') {
  const n = cleanString(next);
  if (n) return n;
  return cleanString(previous);
}

function chooseEnum(next, previous, allowed, fallback) {
  const n = cleanString(next);
  const p = cleanString(previous);

  const nextValid = allowed.includes(n) ? n : '';
  const previousValid = allowed.includes(p) ? p : '';

  if (nextValid && nextValid !== fallback) return nextValid;
  if (previousValid && previousValid !== fallback) return previousValid;
  if (nextValid) return nextValid;
  if (previousValid) return previousValid;

  return fallback;
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function firstArray(...values) {
  for (const value of values) {
    const arr = parseArray(value);
    if (arr.length) return arr;
  }

  return [];
}

function normalizeDog(next = {}, previous = {}) {
  const incoming = isObject(next) ? next : {};
  const prev = isObject(previous) ? previous : {};

  const sexo = chooseEnum(
    incoming.sexo,
    prev.sexo,
    ['macho', 'femea', 'nao_informado'],
    'nao_informado'
  );

  return {
    nome: chooseString(incoming.nome, prev.nome),
    idade_anos: chooseString(incoming.idade_anos, prev.idade_anos),
    idade_texto: chooseString(incoming.idade_texto, prev.idade_texto),
    raca: chooseString(incoming.raca, prev.raca),
    raca_canonica: chooseString(incoming.raca_canonica, prev.raca_canonica),

    porte: chooseEnum(
      incoming.porte,
      prev.porte,
      ['mini', 'pequeno', 'medio', 'grande', 'gigante', 'nao_definido'],
      'nao_definido'
    ),

    sexo,

    castrado: chooseEnum(
      incoming.castrado,
      prev.castrado,
      ['sim', 'nao', 'nao_informado'],
      'nao_informado'
    ),

    no_cio: sexo === 'macho'
      ? 'nao_se_aplica'
      : chooseEnum(
          incoming.no_cio,
          prev.no_cio,
          ['sim', 'nao', 'nao_se_aplica', 'nao_informado'],
          'nao_informado'
        ),

    vacinas_ok: chooseEnum(
      incoming.vacinas_ok,
      prev.vacinas_ok,
      ['sim', 'nao', 'nao_informado'],
      'nao_informado'
    ),

    antipulgas_ok: chooseEnum(
      incoming.antipulgas_ok,
      prev.antipulgas_ok,
      ['sim', 'nao', 'nao_informado'],
      'nao_informado'
    ),

    vermifugacao_ok: chooseEnum(
      incoming.vermifugacao_ok,
      prev.vermifugacao_ok,
      ['sim', 'nao', 'nao_informado'],
      'nao_informado'
    ),

    perfil_comportamental: chooseEnum(
      incoming.perfil_comportamental,
      prev.perfil_comportamental,
      ['nao_informado', 'tranquilo', 'sociavel', 'seletivo', 'reativo_leve', 'reativo_alto', 'agressivo'],
      'nao_informado'
    ),

    comportamento_observacoes: chooseString(
      incoming.comportamento_observacoes,
      prev.comportamento_observacoes
    ),

    possui_relatorio_veterinario: chooseEnum(
      incoming.possui_relatorio_veterinario,
      prev.possui_relatorio_veterinario,
      ['sim', 'nao', 'nao_se_aplica', 'nao_informado'],
      'nao_informado'
    ),

    observacoes: chooseString(incoming.observacoes, prev.observacoes)
  };
}

function normalizeDogArray(value) {
  return parseArray(value)
    .filter(isObject)
    .map(dog => normalizeDog(dog));
}

function mergeDogs(previousDogs, incomingDogs) {
  const previous = normalizeDogArray(previousDogs);
  const incoming = normalizeDogArray(incomingDogs);

  if (!incoming.length) return previous;

  const result = previous.map(dog => ({ ...dog }));

  for (const dog of incoming) {
    const dogName = normalizeText(dog.nome);

    // Caso comum: já existe 1 cão e a Bruna atualizou campos sem repetir o nome.
    if (!dogName && result.length === 1 && incoming.length === 1) {
      result[0] = normalizeDog(dog, result[0]);
      continue;
    }

    const index = dogName
      ? result.findIndex(existing => normalizeText(existing.nome) === dogName)
      : -1;

    if (index >= 0) {
      result[index] = normalizeDog(dog, result[index]);
    } else {
      result.push(normalizeDog(dog));
    }
  }

  return result;
}

function normalizeTipoComprovante(value, comprovanteRecebido) {
  if (comprovanteRecebido !== true) return 'nao_informado';

  return enumValue(
    value,
    ['imagem', 'pdf', 'print_banco', 'nao_informado'],
    'nao_informado'
  );
}

function normalizeMessages(messages) {
  const arr = Array.isArray(messages) ? messages : [];

  return arr
    .map(m => cleanString(m))
    .filter(Boolean)
    .slice(0, 3);
}

function statusLead(value, fallback = 'QUALIFICANDO') {
  return enumValue(
    value,
    [
      'NOVO_LEAD',
      'COLETANDO_DADOS',
      'QUALIFICANDO',
      'PRE_REPROVADO',
      'APTO_PARA_AVALIACAO',
      'AGUARDANDO_PAGAMENTO',
      'COMPROVANTE_RECEBIDO',
      'TRANSFERIDO_FLAVIA',
      'ENCERRADO_NAO_PERFIL',
      'ENCERRADO_SEM_RESPOSTA',
      'ENCERRADO'
    ],
    fallback
  );
}

function ultimaIntencao(value, fallback = 'INTERESSE_CRECHE') {
  return enumValue(
    value,
    [
      'INTERESSE_CRECHE',
      'INTERESSE_HOTEL',
      'PEDIU_VALOR',
      'PEDIU_LOCALIZACAO',
      'PEDIU_VISITA',
      'INFORMOU_DADOS_CAO',
      'INFORMOU_DADOS_TUTOR',
      'ACEITOU_AVALIACAO',
      'RECEBEU_PIX',
      'ENVIOU_COMPROVANTE',
      'PEDIU_HUMANO',
      'MACHO_NAO_CASTRADO',
      'RACA_POTENCIAL_DANO',
      'URGENCIA_FERIADO',
      'OBJECAO_PRECO',
      'SUMIU'
    ],
    fallback
  );
}

function eventoSistema(value) {
  return enumValue(
    value,
    [
      '',
      'FORMULARIO_RECEBIDO',
      'GUIA_ENVIADO',
      'PIX_SOLICITADO',
      'ANEXO_RECEBIDO',
      'COMPROVANTE_IDENTIFICADO',
      'REPASSE_FLAVIA',
      'FOLLOWUP_DISPARADO',
      'CONVERSA_ENCERRADA'
    ],
    ''
  );
}

function statusPagamento(value, normalized) {
  if (normalized.resumo_lead?.comprovante_recebido === true) {
    return 'validacao_humana_pendente';
  }

  if (normalized.deve_solicitar_pagamento === true) {
    return 'aguardando_pagamento';
  }

  return enumValue(
    value,
    [
      'nao_solicitado',
      'aguardando_pagamento',
      'comprovante_recebido',
      'validacao_humana_pendente',
      'aprovado_humano',
      'negado_humano',
      'estornado',
      'cancelado'
    ],
    'nao_solicitado'
  );
}

function isSimpleAck(text) {
  const t = normalizeText(text);

  return [
    'ok',
    'okay',
    'certo',
    'ta bom',
    'tudo bem',
    'obrigado',
    'obrigada',
    'valeu',
    'beleza',
    'blz',
    'show',
    'perfeito',
    'joia',
    'sim',
    'combinado'
  ].includes(t);
}

const start = getNodeJson('Start');
const contextoBruna = getNodeJson('CONTEXTO BRUNA');
const normalizaConfigBruna = getNodeJson('NORMALIZA CONFIG BRUNA');

const base = {
  ...start,
  ...normalizaConfigBruna,
  ...contextoBruna,

  inputs: firstNonEmptyObject(
    contextoBruna.inputs,
    normalizaConfigBruna.inputs,
    start.inputs
  ),

  message: firstNonEmptyObject(
    contextoBruna.message,
    normalizaConfigBruna.message,
    start.message
  ),

  chatwoot: firstNonEmptyObject(
    contextoBruna.chatwoot,
    normalizaConfigBruna.chatwoot,
    start.chatwoot
  ),

  lead: firstNonEmptyObject(
    contextoBruna.lead,
    normalizaConfigBruna.lead,
    start.lead
  ),

  memory: firstNonEmptyObject(
    contextoBruna.memory,
    normalizaConfigBruna.memory,
    start.memory
  )
};

const rawOutput =
  raw.output ??
  raw.text ??
  raw.response ??
  raw.message ??
  raw;

const unwrapped = unwrapBrunaOutput(rawOutput);
const bruna = isObject(unwrapped.bruna) ? unwrapped.bruna : {};

const previousInputs = base.inputs || {};
const previousResumo = previousInputs.resumo_lead || {};
const previousRepasse = previousInputs.resumo_interno_repasse || {};

const configBruna = firstNonEmptyObject(
  contextoBruna.config_bruna,
  normalizaConfigBruna.config_bruna,
  start.config_bruna,
  raw.config_bruna
);

const previousDogs = firstArray(
  previousInputs.caes_json,
  previousResumo.caes_json,
  previousRepasse.caes_json,
  base.memory?.caes_json
);

const incomingDogs = firstArray(
  bruna.resumo_lead?.caes_json,
  bruna.resumo_interno_repasse?.caes_json,
  bruna.caes_json
);

const caesJson = mergeDogs(previousDogs, incomingDogs);
const quantidadeCaes = caesJson.length;

const deveRepassarHumano = toBool(bruna.deve_repassar_humano);
const comprovanteRecebido = toBool(
  bruna.resumo_lead?.comprovante_recebido ??
  bruna.comprovante_recebido ??
  previousResumo.comprovante_recebido ??
  previousInputs.comprovante_recebido
);

const unidadePreferida = enumValue(
  bruna.resumo_lead?.unidade_preferida ||
  previousResumo.unidade_preferida,
  ['amaralina', 'auauzin_patamares', 'nao_definida'],
  'nao_definida'
);

const servicoInteresse = enumValue(
  bruna.resumo_lead?.servico_interesse ||
  previousResumo.servico_interesse,
  ['creche', 'hotel', 'creche_e_hotel', 'visita', 'nao_definido'],
  'nao_definido'
);

const resumoLead = {
  tutor_nome: cleanString(bruna.resumo_lead?.tutor_nome || previousResumo.tutor_nome || base.lead?.sender_name),
  tutor_telefone: cleanString(bruna.resumo_lead?.tutor_telefone || previousResumo.tutor_telefone || base.lead?.phone),
  email_tutor: cleanString(bruna.resumo_lead?.email_tutor || previousResumo.email_tutor),

  quantidade_caes: quantidadeCaes,
  caes_json: caesJson,

  unidade_preferida: unidadePreferida,
  servico_interesse: servicoInteresse,

  periodo_desejado: cleanString(bruna.resumo_lead?.periodo_desejado || previousResumo.periodo_desejado),
  data_desejada: cleanString(bruna.resumo_lead?.data_desejada || previousResumo.data_desejada),
  data_checkin_desejada: cleanString(bruna.resumo_lead?.data_checkin_desejada || previousResumo.data_checkin_desejada),
  data_checkout_desejada: cleanString(bruna.resumo_lead?.data_checkout_desejada || previousResumo.data_checkout_desejada),

  origem_lead: cleanString(bruna.resumo_lead?.origem_lead || previousResumo.origem_lead || 'outro'),
  origem_detalhada: cleanString(bruna.resumo_lead?.origem_detalhada || previousResumo.origem_detalhada || base.lead?.entry_channel),

  comprovante_recebido: comprovanteRecebido,
  tipo_comprovante: normalizeTipoComprovante(
    bruna.resumo_lead?.tipo_comprovante || previousResumo.tipo_comprovante,
    comprovanteRecebido
  ),
  arquivo_comprovante_referencia: cleanString(
    bruna.resumo_lead?.arquivo_comprovante_referencia ||
    previousResumo.arquivo_comprovante_referencia
  ),

  data_hora_avaliacao: '',
  data_hora_pre_reserva: '',
  pre_reserva_criada: false,

  responsavel_humano: deveRepassarHumano ? 'Flavia' : '',

  observacoes: cleanString(bruna.resumo_lead?.observacoes || previousResumo.observacoes)
};

const resumoInternoRepasse = {
  repassar_para: deveRepassarHumano ? 'Flavia' : '',
  motivo: deveRepassarHumano
    ? cleanString(bruna.resumo_interno_repasse?.motivo || bruna.motivo_repasse)
    : '',

  tutor_nome: resumoLead.tutor_nome,
  tutor_telefone: resumoLead.tutor_telefone,

  quantidade_caes: quantidadeCaes,
  caes_json: caesJson,

  unidade_preferida: resumoLead.unidade_preferida,
  servico_interesse: resumoLead.servico_interesse,

  data_hora_avaliacao: '',
  comprovante_recebido: resumoLead.comprovante_recebido,
  tipo_comprovante: resumoLead.tipo_comprovante,
  observacoes: cleanString(
    bruna.resumo_interno_repasse?.observacoes ||
    previousRepasse.observacoes ||
    resumoLead.observacoes
  )
};

const normalizedBase = {
  status_lead: statusLead(
    bruna.status_lead,
    previousInputs.status_lead || 'QUALIFICANDO'
  ),

  ultima_intencao: ultimaIntencao(
    bruna.ultima_intencao,
    previousInputs.ultima_intencao || 'INTERESSE_CRECHE'
  ),

  evento_sistema: eventoSistema(bruna.evento_sistema),

  mensagens_resposta: normalizeMessages(bruna.mensagens_resposta),

  resumo_lead: resumoLead,

  proxima_acao: cleanString(
    bruna.proxima_acao ||
    previousInputs.proxima_acao ||
    'Aguardar próxima interação do lead.'
  ),

  deve_repassar_humano: deveRepassarHumano,
  motivo_repasse: deveRepassarHumano
    ? cleanString(bruna.motivo_repasse || resumoInternoRepasse.motivo)
    : '',

  deve_enviar_guia: toBool(bruna.deve_enviar_guia),
  deve_solicitar_pagamento: toBool(bruna.deve_solicitar_pagamento),

  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: toBool(bruna.deve_encerrar_conversa),

  resumo_interno_repasse: resumoInternoRepasse
};

const normalizedInputs = {
  status_lead: normalizedBase.status_lead,
  ultima_intencao: normalizedBase.ultima_intencao,
  evento_sistema: normalizedBase.evento_sistema,

  apto_para_avaliacao: enumValue(
    bruna.apto_para_avaliacao || previousInputs.apto_para_avaliacao,
    ['sim', 'nao', 'caso_cinzento', 'pendente'],
    'pendente'
  ),

  motivo_pre_reprovacao: cleanString(
    bruna.motivo_pre_reprovacao ||
    previousInputs.motivo_pre_reprovacao
  ),

  status_pagamento: statusPagamento(previousInputs.status_pagamento, normalizedBase),

  comprovante_recebido: resumoLead.comprovante_recebido,
  tipo_comprovante: resumoLead.tipo_comprovante,
  arquivo_comprovante_referencia: resumoLead.arquivo_comprovante_referencia,

  pre_reserva_criada: false,
  data_hora_avaliacao: '',
  data_hora_pre_reserva: '',

  quantidade_caes: quantidadeCaes,
  caes_json: caesJson,

  resumo_lead: resumoLead,

  proxima_acao: normalizedBase.proxima_acao,

  deve_repassar_humano: normalizedBase.deve_repassar_humano,
  motivo_repasse: normalizedBase.motivo_repasse,

  deve_enviar_guia: normalizedBase.deve_enviar_guia,
  deve_solicitar_pagamento: normalizedBase.deve_solicitar_pagamento,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: normalizedBase.deve_encerrar_conversa,

  resumo_interno_repasse: resumoInternoRepasse,

  regras_raca: firstNonEmptyObject(
    base.regras_raca,
    previousInputs.regras_raca
  ),

  diagnostico_crm: isObject(previousInputs.diagnostico_crm)
    ? previousInputs.diagnostico_crm
    : {},

  precisa_responder_preco: toBool(previousInputs.precisa_responder_preco),
  precisa_responder_localizacao: toBool(previousInputs.precisa_responder_localizacao),
  precisa_responder_visita_material: toBool(previousInputs.precisa_responder_visita_material),
  deve_priorizar_base_conhecimento: toBool(previousInputs.deve_priorizar_base_conhecimento),
  is_first_turn: toBool(previousInputs.is_first_turn)
};

const currentLeadText = cleanString(
  base.message?.current_lead_block_text ||
  base.message?.content ||
  ''
);

const lastHumanMessageBeforeCurrentBlock = cleanString(
  base.message?.last_human_message_before_current_block
);

const labels = Array.isArray(base.chatwoot?.labels) ? base.chatwoot.labels : [];

const humanoAssumiu =
  normalizedInputs.diagnostico_crm?.humano_assumiu === true ||
  labels.includes('01-humano-assumiu') ||
  lastHumanMessageBeforeCurrentBlock !== '';

const leadApenasConfirmou = isSimpleAck(currentLeadText);

const bloquearRespostaPorHumano =
  humanoAssumiu === true &&
  leadApenasConfirmou === true;

let shouldReply = base.should_reply !== false;
let motivoBloqueioEnvio = '';

if (normalizedBase.mensagens_resposta.length === 0) {
  shouldReply = false;
  motivoBloqueioEnvio = 'sem_mensagem_resposta_valida';

  normalizedInputs.mensagens_resposta = [];
  normalizedInputs.deve_enviar_guia = false;
  normalizedInputs.deve_solicitar_pagamento = false;
  normalizedInputs.deve_repassar_humano = false;
  normalizedInputs.motivo_repasse = '';
  normalizedInputs.deve_consultar_agenda = false;
  normalizedInputs.deve_criar_pre_reserva = false;
  normalizedInputs.evento_sistema = '';
  normalizedInputs.proxima_acao = 'Não responder: saída da Bruna sem mensagem válida.';
}

if (unwrapped.parse_error === true) {
  shouldReply = false;
  motivoBloqueioEnvio = 'erro_parse_saida_bruna';

  normalizedInputs.mensagens_resposta = [];
  normalizedInputs.deve_enviar_guia = false;
  normalizedInputs.deve_solicitar_pagamento = false;
  normalizedInputs.deve_repassar_humano = false;
  normalizedInputs.motivo_repasse = '';
  normalizedInputs.deve_consultar_agenda = false;
  normalizedInputs.deve_criar_pre_reserva = false;
  normalizedInputs.evento_sistema = '';
  normalizedInputs.proxima_acao = 'Não responder: erro ao interpretar saída da Bruna.';
}

if (bloquearRespostaPorHumano) {
  shouldReply = false;
  motivoBloqueioEnvio = 'humano_assumiu_e_lead_apenas_confirmou';

  normalizedInputs.mensagens_resposta = [];
  normalizedInputs.deve_enviar_guia = false;
  normalizedInputs.deve_solicitar_pagamento = false;
  normalizedInputs.deve_repassar_humano = false;
  normalizedInputs.motivo_repasse = '';
  normalizedInputs.deve_consultar_agenda = false;
  normalizedInputs.deve_criar_pre_reserva = false;
  normalizedInputs.evento_sistema = '';
  normalizedInputs.proxima_acao = 'Não responder: atendimento humano já assumido e lead apenas confirmou.';
}

const mensagensRespostaFinais = shouldReply
  ? normalizedBase.mensagens_resposta
  : [];

return [
  {
    json: {
      inputs: {
        ...normalizedInputs,
        mensagens_resposta: mensagensRespostaFinais
      },

      message: base.message || {},
      chatwoot: base.chatwoot || {},
      lead: base.lead || {},
      memory: base.memory || {},

      caes_json: caesJson,
      quantidade_caes: quantidadeCaes,

      config_bruna: configBruna,

      agent_name: base.agent_name || 'Bruna',
      should_reply: shouldReply,
      motivo_bloqueio_envio: motivoBloqueioEnvio,

