function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function parseValue(value) {
  if (value === undefined || value === null) return {};

  if (isObject(value) || Array.isArray(value)) {
    return value;
  }

  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return {};

    try {
      return JSON.parse(text);
    } catch (e) {
      return {};
    }
  }

  return value;
}

function isTruthy(value) {
  return (
    value === true ||
    value === 1 ||
    value === '1' ||
    String(value).toLowerCase() === 'true'
  );
}

function cleanString(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value).trim();
}

function toBool(value) {
  return value === true || value === 1 || value === '1' || String(value).toLowerCase() === 'true';
}

function enumValue(value, allowed, fallback) {
  const v = cleanString(value);
  return allowed.includes(v) ? v : fallback;
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function firstArray(...values) {
  for (const value of values) {
    const arr = parseArray(value);
    if (arr.length) return arr;
  }

  return [];
}

function normalizeDog(raw = {}) {
  const dog = isObject(raw) ? raw : {};

  const sexo = enumValue(dog.sexo, ['macho', 'femea', 'nao_informado'], 'nao_informado');

  return {
    nome: cleanString(dog.nome),
    idade_anos: cleanString(dog.idade_anos),
    idade_texto: cleanString(dog.idade_texto),
    raca: cleanString(dog.raca),
    raca_canonica: cleanString(dog.raca_canonica),
    porte: enumValue(dog.porte, ['mini', 'pequeno', 'medio', 'grande', 'gigante', 'nao_definido'], 'nao_definido'),
    sexo,
    castrado: enumValue(dog.castrado, ['sim', 'nao', 'nao_informado'], 'nao_informado'),
    no_cio: sexo === 'macho'
      ? 'nao_se_aplica'
      : enumValue(dog.no_cio, ['sim', 'nao', 'nao_se_aplica', 'nao_informado'], 'nao_informado'),
    vacinas_ok: enumValue(dog.vacinas_ok, ['sim', 'nao', 'nao_informado'], 'nao_informado'),
    antipulgas_ok: enumValue(dog.antipulgas_ok, ['sim', 'nao', 'nao_informado'], 'nao_informado'),
    vermifugacao_ok: enumValue(dog.vermifugacao_ok, ['sim', 'nao', 'nao_informado'], 'nao_informado'),
    perfil_comportamental: enumValue(
      dog.perfil_comportamental,
      ['nao_informado', 'tranquilo', 'sociavel', 'seletivo', 'reativo_leve', 'reativo_alto', 'agressivo'],
      'nao_informado'
    ),
    comportamento_observacoes: cleanString(dog.comportamento_observacoes),
    possui_relatorio_veterinario: enumValue(
      dog.possui_relatorio_veterinario,
      ['sim', 'nao', 'nao_se_aplica', 'nao_informado'],
      'nao_informado'
    ),
    observacoes: cleanString(dog.observacoes)
  };
}

