    const temValorModelo =
      row.regra_valor_modelo !== undefined &&
      row.regra_valor_modelo !== null &&
      String(row.regra_valor_modelo).trim() !== '';

    config_bruna_modelo[key] = temValorModelo
      ? parseValue(row.regra_valor_modelo)
      : valorCompleto;
  }
}

